```typescript
interface IRepository<T> {
  getAll(): T[];
  get(id: number): T;
  save(data: T): void;
  update(id: number, data: T): void;
  delete(id: number): void;
}

class InMemoryRepository<T> implements IRepository<T> {
  private data: T[];

  constructor() {
    this.data = [];
  }

  public getAll(): T[] {
    return this.data;
  }

  public get(id: number): T {
    return this.data.find(item => item.id === id);
  }

  public save(data: T): void {
    this.data.push(data);
  }

  public update(id: number, data: T): void {
    const index = this.data.findIndex(item => item.id === id);
    if (index !== -1) {
      this.data[index] = data;
    }
  }

  public delete(id: number): void {
    this.data = this.data.filter(item => item.id !== id);
  }
}

class Service<T> {
  private repository: InMemoryRepository<T>;

  constructor(repository: InMemoryRepository<T>) {
    this.repository = repository;
  }

  public getAll(): T[] {
    return this.repository.getAll();
  }

  public save(data: T): void {
    this.repository.save(data);
  }

  public update(id: number, data: T): void {
    this.repository.update(id, data);
  }

  public delete(id: number): void {
    this.repository.delete(id);
  }
}

// Example usage
const repository: InMemoryRepository<{ id: number; name: string }> = new InMemoryRepository();
const service: Service<{ id: number; name: string }> = new Service(repository);

repository.save({ id: 1, name: 'John' });

console.log(service.getAll());
service.update(1, { id: 1, name: 'Jane' });
console.log(service.getAll());
service.delete(1);
console.log(service.getAll());
```
